<?php require_once __DIR__.'/../../config/app.php'; requireAuth(); $pageTitle='Attendance';
if($_SERVER['REQUEST_METHOD']==='POST'){verifyCsrf(); if(post('type')==='student'){executeSql('INSERT INTO attendance_students(student_id,attendance_date,status) VALUES (?,?,?) ON DUPLICATE KEY UPDATE status=VALUES(status)',[(int)post('student_id'),post('attendance_date'),post('status')]);} else {executeSql('INSERT INTO attendance_faculty(faculty_id,attendance_date,check_in,check_out) VALUES (?,?,?,?) ON DUPLICATE KEY UPDATE check_in=VALUES(check_in),check_out=VALUES(check_out)',[(int)post('faculty_id'),post('attendance_date'),post('check_in'),post('check_out')]);} header('Location: index.php'); exit; }
$students=fetchAll('SELECT id,full_name FROM students ORDER BY full_name'); $faculty=fetchAll('SELECT id,full_name FROM faculty ORDER BY full_name');
$report=fetchAll('SELECT s.full_name, ROUND(100*SUM(a.status="Present")/COUNT(*),2) attendance_pct FROM attendance_students a JOIN students s ON s.id=a.student_id WHERE DATE_FORMAT(a.attendance_date,"%Y-%m")=DATE_FORMAT(CURDATE(),"%Y-%m") GROUP BY s.id ORDER BY attendance_pct DESC');
include __DIR__.'/../../includes/header.php'; include __DIR__.'/../../includes/sidebar.php'; ?><main class="content-wrap"><?php include __DIR__.'/../../includes/topbar.php'; ?><section class="panel glass"><h5>Mark Student Attendance</h5><form method="post" class="row g-2"><?=csrfField()?><input type="hidden" name="type" value="student"><div class="col"><select name="student_id" class="form-select"><?php foreach($students as $s):?><option value="<?=$s['id']?>"><?=e($s['full_name'])?></option><?php endforeach;?></select></div><div class="col"><input name="attendance_date" type="date" value="<?=date('Y-m-d')?>" class="form-control"></div><div class="col"><select name="status" class="form-select"><option>Present</option><option>Absent</option></select></div><div class="col"><button class="btn btn-primary">Save</button></div></form><hr><h5>Faculty Check In/Out</h5><form method="post" class="row g-2"><?=csrfField()?><input type="hidden" name="type" value="faculty"><div class="col"><select name="faculty_id" class="form-select"><?php foreach($faculty as $f):?><option value="<?=$f['id']?>"><?=e($f['full_name'])?></option><?php endforeach;?></select></div><div class="col"><input name="attendance_date" type="date" value="<?=date('Y-m-d')?>" class="form-control"></div><div class="col"><input name="check_in" type="time" class="form-control"></div><div class="col"><input name="check_out" type="time" class="form-control"></div><div class="col"><button class="btn btn-primary">Save</button></div></form><hr><h5>Monthly Report</h5><table class="table"><tr><th>Student</th><th>%</th></tr><?php foreach($report as $r):?><tr><td><?=e($r['full_name'])?></td><td><?=$r['attendance_pct']?>%</td></tr><?php endforeach;?></table></section></main><?php include __DIR__.'/../../includes/footer.php'; ?>
